package com.manhmoc.edgebar;
import android.content.Intent; import android.provider.Settings; import android.service.quicksettings.Tile; import android.service.quicksettings.TileService;
public class EdgeBarTileService extends TileService {
    @Override public void onClick() { super.onClick(); try { String srv = "com.manhmoc.edgebar.v17/com.manhmoc.edgebar.EdgeBarService"; String en = Settings.Secure.getString(getContentResolver(), Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES); if (en == null) en = ""; boolean isEn = en.contains(srv); if (isEn) { en = en.replace(srv, "").replace("::", ":"); if (en.endsWith(":")) en = en.substring(0, en.length() - 1); } else { en = en.isEmpty() ? srv : en + ":" + srv; Settings.Secure.putInt(getContentResolver(), Settings.Secure.ACCESSIBILITY_ENABLED, 1); } Settings.Secure.putString(getContentResolver(), Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES, en); Tile t = getQsTile(); t.setState(isEn ? Tile.STATE_INACTIVE : Tile.STATE_ACTIVE); t.updateTile(); 
    if (Settings.canDrawOverlays(this) && !HomescreenService.isRunning) { Intent sInt = new Intent(this, HomescreenService.class); if (android.os.Build.VERSION.SDK_INT >= 26) startForegroundService(sInt); else startService(sInt); } } catch (Exception e) {} }
    @Override public void onStartListening() { super.onStartListening(); String srv = "com.manhmoc.edgebar.v17/com.manhmoc.edgebar.EdgeBarService"; String en = Settings.Secure.getString(getContentResolver(), Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES); Tile t = getQsTile(); t.setState((en != null && en.contains(srv)) ? Tile.STATE_ACTIVE : Tile.STATE_INACTIVE); t.updateTile(); }
}
